FUNCTION LCG(seed, a, c, m):
 state ← seed
 WHILE true DO
 state ← (a * state + c) MOD m
 OUTPUT state
 END WHILE
END FUNCTION

// Example parameters (MINSTD)
a ← 48271
c ← 0
m ← 2147483647
seed ← system_entropy()

